import React, {useState, useEffect} from "react";
import "./uploadposterCSS.css";
import Navbaremployee from "./upperlistemployee";
import Cookies from "universal-cookie";

export const UploadPoster = () => {
    const [search, setSearch] = useState('');
    const cookies=new Cookies();
    
    useEffect(() => {
        cookies.set('search',search,{path:'/'});
        console.log(cookies)
    },[search])

    const [imageUrl, setImageUrl] = useState('');
    const [imageSrc, setImageSrc] = useState('');
    const [error, setError] = useState('');

    const downloadAndDisplayImage = async () => {
        try {
            // 獲取圖像
            const response = await fetch(imageUrl);
            if (!response.ok) {
                throw new Error('无法加载图像，请检查输入的URL。');
            }

            const blob = await response.blob();
            const url = URL.createObjectURL(blob);

            setImageSrc(url);
            setError('');
        } catch (err) {
            setError(err.message);
            setImageSrc('');
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        downloadAndDisplayImage();
    };

    return(
        <>
            {/* <Navbaremployee setSearch={setSearch}/> */}
            {/* https://ottaster.com/js-upload-file/ */}
            <form onSubmit={handleSubmit}>
                <label>
                    宣傳海報上傳
                    <input
                        type="text"
                        value={imageUrl}
                        onChange={(e) => setImageUrl(e.target.value)}
                    />
                </label>
                <button type="submit">提交</button>
            </form>

            {error && <p style={{ color: 'red' }}>{error}</p>}

            {imageSrc && (
                <div>
                    <img src={imageSrc} alt="input_image" />
                </div>
            )}
        </>
    );
};
export default UploadPoster;
